<template>
  <div style="margin: 8px 16px 0;">
    <a-table bordered :data-source="dataSource" :columns="columns" size="small">
      <template #bodyCell="{ column, record }">
        <template v-if="column.dataIndex === 'operation'">
          <a-popconfirm v-if="dataSource.length" title="Sure to delete?"
            @confirm="onDelete(record.geneName, record.spacer)">
            <a>Delete</a>
          </a-popconfirm>
        </template>
      </template>
    </a-table>
  </div>
</template>

<script>

export default {
  name: 'StepShow20nt',
  props: {
    sequence20nt: {
      type: Array,
      required: true,
    },
    initParamsData: {
      type: Object,
      required: true,
    },
  },
  emits: ['updateSequence20nt'],
  methods: {
    onDelete(geneName, spacer) {
      this.dataSource.splice(
        this.dataSource.findIndex(item => item.geneName === geneName && item.spacer === spacer),
        1,
      );
    },
  },
  watch: {
    dataSource: {
      deep: true,
      handler(newValue) {
        console.log('updateSequence20nt', newValue)
        this.$emit('updateSequence20nt', newValue);
      },
      immediate: true,
    }
  },
  data: () => ({
    dataSource: [
      // {
      //   key: '0',
      //   geneName: 'gene1',
      //   sequence: 'GTGTCATAGCCCAGCTTGGCGGGCGAAGGCCAAGAC',
      // },
      // {
      //   key: '1',
      //   geneName: 'gene1',
      //   sequence: 'GTGTCATAGCCCAGCTTGGCGGGCGAAGGCCAAGAC',
      // },
    ],
    columns: [
      {
        title: 'Gene',
        dataIndex: 'geneName',
      },
      {
        title: 'Optional spacer',
        dataIndex: 'spacer',
      },
      {
        title: 'Operation',
        dataIndex: 'operation',
      },
    ],
  }),
  beforeMount() {
    this.columns[1].title = 'Spacer' // `${this.initParamsData.targetLength}nt Sequence`
    // this.$emit('updateSequence20nt', this.dataSource)
    // eslint-disable-next-line no-undef
    pywebview.api.getSpacer().then((item) => {
      this.dataSource = item
      console.log(this.dataSource)
    })
  },
}
</script>
